### Basic Text Input Usage Example

Source: https://github.com/charmbracelet/bubbles/blob/main/_autodocs/api-reference/textinput.md

A complete Bubble Tea application demonstrating the basic usage of the textinput component, including initialization, focus, and handling user input.

```go
package main

import (
	"fmt"
	"log"

tea "charm.land/bubbletea/v2"
	"charm.land/bubbles/v2/textinput"
)

type Model struct {
	input textinput.Model
}

func (m Model) Init() tea.Cmd {
	return m.input.Focus()
}

func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyPressMsg:
		if msg.String() == "enter" {
			return m, tea.Quit
		}
	}

	var cmd tea.Cmd
	m.input, cmd = m.input.Update(msg)
	return m, cmd
}

func (m Model) View() string {
	return fmt.Sprintf(
		"Enter your name:\n%s\n(press enter to quit)\n",
		m.input.View(),
	)
}

func main() {
	input := textinput.New()
	input.Placeholder = "Jane Doe"
	input.Focus()

	m := Model{input: input}
	p := tea.NewProgram(m)
	if _, err := p.Run(); err != nil {
		log.Fatal(err)
	}
}
```

--------------------------------

### Spinner Usage Example

Source: https://github.com/charmbracelet/bubbles/blob/main/_autodocs/api-reference/spinner.md

A complete Bubble Tea application demonstrating how to use the spinner component to show a loading indicator. The spinner ticks and updates its view until the user presses 'q' to quit.

```go
package main

import (
	"fmt"
	"time"

	tea "charm.land/bubbletea/v2"
	"charm.land/bubbles/v2/spinner"
)

type Model struct {
	spinner spinner.Model
	done    bool
}

func (m Model) Init() tea.Cmd {
	return m.spinner.Tick()
}

func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyPressMsg:
		if msg.String() == "q" {
			m.done = true
		}
	case spinner.TickMsg:
		var cmd tea.Cmd
		m.spinner, cmd = m.spinner.Update(msg)
		return m, cmd
	}
	return m, nil
}

func (m Model) View() string {
	if m.done {
		return "Done!\n"
	}
	return fmt.Sprintf("Loading... %s\n", m.spinner.View())
}

func main() {
	m := Model{spinner: spinner.New()}
	if _, err := tea.NewProgram(m).Run(); err != nil {
		panic(err)
	}
}
