### Table Usage Example

Source: https://github.com/charmbracelet/bubbles/blob/main/_autodocs/api-reference/table.md

A complete Bubble Tea application demonstrating the integration and usage of the Table component. It shows initialization, updating, and rendering.

```go
package main

import (
	"fmt"
	"log"

	tea "charm.land/bubbletea/v2"
	"charm.land/bubbles/v2/table"
)

type Model struct {
	table table.Model
}

func (m Model) Init() tea.Cmd {
	return nil
}

func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	var cmd tea.Cmd
	m.table, cmd = m.table.Update(msg)

	sswitch msg := msg.(type) {
	case tea.KeyPressMsg:
		switch msg.String() {
		case "q", "esc", "ctrl+c":
			return m, tea.Quit
		}
	case tea.WindowSizeMsg:
		m.table.SetWidth(msg.Width)
		m.table.SetHeight(msg.Height - 4)
	}
	return m, cmd
}

func (m Model) View() string {
	return fmt.Sprintf(
		"Table\n%s\n(Press q to quit)",
		m.table.View(),
	)
}

func main() {
	columns := []table.Column{
		{Title: "ID", Width: 4},
		{Title: "Name", Width: 15},
		{Title: "Country", Width: 10},
	}


rows := []table.Row{
		{"1", "Ramsés II", "Egypt"},
		{"2", "Ramesses III", "Egypt"},
		{"3", "Khafre", "Egypt"},
	}

	t := table.New(
		table.WithColumns(columns),
		table.WithRows(rows),
		table.WithHeight(7),
		table.WithFocused(true),
	)

	m := Model{table: t}
	p := tea.NewProgram(m)
	if _, err := p.Run(); err != nil {
		log.Fatal(err)
	}
}

```

